// MARK: - Secure Configuration Manager
// Secrets are loaded from environment variables, a secure keychain store,
// or a configuration file that is NOT checked into source control.

final class SecretsManager {
    static let shared = SecretsManager()
    
    private init() {}
    
    enum SecretKey: String {
        case googleMapsAPIKey = "GOOGLE_MAPS_API_KEY"
        case stripePublishableKey = "STRIPE_PUBLISHABLE_KEY"
    }
    
    /// Retrieves a secret by first checking the Keychain, then falling back
    /// to a local Secrets.plist (gitignored), then environment variables.
    func secret(for key: SecretKey) -> String? {
        // 1. Try Keychain
        if let keychainValue = readFromKeychain(key: key.rawValue) {
            return keychainValue
        }
        
        // 2. Try Secrets.plist (must be in .gitignore, never committed)
        if let plistValue = readFromSecretsPlist(key: key.rawValue) {
            return plistValue
        }
        
        // 3. Try environment variable (useful for CI/CD)
        if let envValue = ProcessInfo.processInfo.environment[key.rawValue], !envValue.isEmpty {
            return envValue
        }
        
        return nil
    }
    
    // MARK: - Keychain Helpers
    
    func storeInKeychain(key: String, value: String) -> Bool {
        guard let data = value.data(using: .utf8) else { return false }
        
        // Delete any existing item first
        let deleteQuery: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecAttrService as String: Bundle.main.bundleIdentifier ?? "com.app.demo"
        ]
        SecItemDelete(deleteQuery as CFDictionary)
        
        let addQuery: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecAttrService as String: Bundle.main.bundleIdentifier ?? "com.app.demo",
            kSecValueData as String: data,
            kSecAttrAccessible as String: kSecAttrAccessibleWhenUnlockedThisDeviceOnly
        ]
        
        let status = SecItemAdd(addQuery as CFDictionary, nil)
        return status == errSecSuccess
    }
    
    private func readFromKeychain(key: String) -> String? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecAttrService as String: Bundle.main.bundleIdentifier ?? "com.app.demo",
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        guard status == errSecSuccess, let data = result as? Data else {
            return nil
        }
        return String(data: data, encoding: .utf8)
    }
    
    private func readFromSecretsPlist(key: String) -> String? {
        guard let path = Bundle.main.path(forResource: "Secrets", ofType: "plist"),
              let dict = NSDictionary(contentsOfFile: path),
              let value = dict[key] as? String,
              !value.isEmpty,
              !value.hasPrefix("YOUR_") else {
            return nil
        }
        return value
    }
}

// MARK: - App Delegate

@main
class AppDelegate: UIResponder, UIApplicationDelegate {
    
    var window: UIWindow?
    
    func application(
        _ application: UIApplication,
        didFinishLaunchingWithOptions launchOptions: [UIApplication.LaunchOptionsKey: Any]?
    ) -> Bool {
        
        configureGoogleMaps()
        configureStripe()
        
        window = UIWindow(frame: UIScreen.main.bounds)
        
        let secretsConfigured = SecretsManager.shared.secret(for: .googleMapsAPIKey) != nil
            && SecretsManager.shared.secret(for: .stripePublishableKey) != nil
        
        if secretsConfigured {
            window?.rootViewController = UINavigationController(rootViewController: MainViewController())
        } else {
            window?.rootViewController = UINavigationController(rootViewController: SetupViewController())
        }
        
        window?.makeKeyAndVisible()
        return true
    }
    
    private func configureGoogleMaps() {
        guard let apiKey = SecretsManager.shared.secret(for: .googleMapsAPIKey) else {
            print("⚠️ Google Maps API key not configured. Please set up via Secrets.plist or Keychain.")
            return
        }
        GMSServices.provideAPIKey(apiKey)
    }
    
    private func configureStripe() {
        guard let publishableKey = SecretsManager.shared.secret(for: .stripePublishableKey) else {
            print("⚠️ Stripe publishable key not configured. Please set up via Secrets.plist or Keychain.")
            return
        }
        StripeAPI.defaultPublishableKey = publishableKey
    }
}

