// MARK: - Map View Controller

class MapViewController: UIViewController {
    
    private var mapView: GMSMapView!
    
    override func viewDidLoad() {
        super.viewDidLoad()
        title = "Service Area"
        view.backgroundColor = .systemBackground
        setupMap()
    }
    
    private func setupMap() {
        let options = GMSMapViewOptions()
        let camera = GMSCameraPosition.camera(
            withLatitude: 37.7749,
            longitude: -122.4194,
            zoom: 12.0
        )
        options.camera = camera
        
        mapView = GMSMapView(options: options)
        mapView.translatesAutoresizingMaskIntoConstraints = false
        view.addSubview(mapView)
        
        NSLayoutConstraint.activate([
            mapView.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor),
            mapView.bottomAnchor.constraint(equalTo: view.bottomAnchor),
            mapView.leadingAnchor.constraint(equalTo: view.leadingAnchor),
            mapView.trailingAnchor.constraint(equalTo: view.trailingAnchor)
        ])
        
        addSampleMarkers()
    }
    
    private func addSampleMarkers() {
        let locations: [(String, Double, Double)] = [
            ("Service Point A", 37.7849, -122.4094),
            ("Service Point B", 37.7649, -122.4294),
            ("Service Point C", 37.7749, -122.4394),
            ("Headquarters", 37.7899, -122.3994)
        ]
        
        for (title, lat, lng) in locations {
            let marker = GMSMarker()
            marker.position = CLLocationCoordinate2D(latitude: lat, longitude: lng)
            marker.title = title
            marker.snippet = "Tap for details"
            marker.map = mapView
        }
    }
}

