class PaymentViewController: UIViewController {
    
    private let amountLabel = UILabel()
    private let cardTextField = STPPaymentCardTextField()
    private let payButton = UIButton(type: .system)
    private let statusLabel = UILabel()
    private let stackView = UIStackView()
    
    private let demoAmount: Int = 4999 // $49.99 in cents
    
    override func viewDidLoad() {
        super.viewDidLoad()
        title = "Payment"
        view.backgroundColor = .systemBackground
        setupUI()
    }
    
    private func setupUI() {
        amountLabel.text = "Total: $49.99"
        amountLabel.font = .systemFont(ofSize: 36, weight: .bold)
        amountLabel.textAlignment = .center
        
        let descriptionLabel = UILabel()
        descriptionLabel.text = "Premium Service Package"
        descriptionLabel.font = .systemFont(ofSize: 16)
        descriptionLabel.textColor = .secondaryLabel
        descriptionLabel.textAlignment = .center
        
        cardTextField.postalCodeEntryEnabled = true
        cardTextField.heightAnchor.constraint(equalToConstant: 50).isActive = true
        
        payButton.setTitle("Pay Now", for: .normal)
        payButton.titleLabel?.font = .systemFont(ofSize: 20, weight: .semibold)
        payButton.backgroundColor = .systemBlue
        payButton.setTitleColor(.white, for: .normal)
        payButton.layer.cornerRadius = 14
        payButton.heightAnchor.constraint(equalToConstant: 56).isActive = true
        payButton.addTarget(self, action: #selector(payTapped), for: .touchUpInside)
        
        statusLabel.text = ""
        statusLabel.font = .systemFont(ofSize: 14)
        statusLabel.textAlignment = .center
        statusLabel.numberOfLines = 0
        
        stackView.axis = .vertical
        stackView.spacing = 16
        stackView.translatesAutoresizingMaskIntoConstraints = false
        
        [amountLabel, descriptionLabel, cardTextField, payButton, statusLabel].forEach {
            stackView.addArrangedSubview($0)
        }
        
        stackView.setCustomSpacing(8, after: amountLabel)
        stackView.setCustomSpacing(32, after: descriptionLabel)
        
        view.addSubview(stackView)
        NSLayoutConstraint.activate([
            stackView.centerYAnchor.constraint(equalTo: view.centerYAnchor, constant: -20),
            stackView.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 32),
            stackView.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -32)
        ])
    }
    
    @objc private func payTapped() {
        guard cardTextField.isValid else {
            statusLabel.text = "⚠️ Please enter valid card details."
            statusLabel.textColor = .systemOrange
            return
        }
        
        payButton.isEnabled = false
        payButton.backgroundColor = .systemGray
        statusLabel.text = "Processing..."
        statusLabel.textColor = .label
        
        guard let paymentMethodParams = cardTextField.paymentMethodParams as STPPaymentMethodParams? else {
            statusLabel.text = "❌ Could not create payment method."
            statusLabel.textColor = .systemRed
            payButton.isEnabled = true
            payButton.backgroundColor = .systemBlue
            return
        }
        
        // In production, the PaymentIntent client secret comes from YOUR backend server.
        // The backend creates the PaymentIntent using the Stripe SECRET key (never in the app).
        // For demo: call your backend endpoint to get the client secret.
        
        fetchPaymentIntentClientSecret { [weak self] result in
            DispatchQueue.main.async {
                guard let self = self else { return }
                
                switch result {
                case .success(let clientSecret):
                    let paymentIntentParams = STPPaymentIntentParams(clientSecret: clientSecret)
                    paymentIntentParams.paymentMethodParams = paymentMethodParams
                    
                    STPPaymentHandler.shared().confirmPayment(paymentIntentParams, with: self) { status, _, error in
                        switch status {
                        case .succeeded:
                            self.statusLabel.text = "✅ Payment successful!"
                            self.statusLabel.textColor = .systemGreen
                        case .canceled:
                            self.statusLabel.text = "Payment canceled."
                            self.statusLabel.textColor = .systemOrange
                            self.payButton.isEnabled = true
                            self.payButton.backgroundColor = .systemBlue
                        case .failed:
                            self.statusLabel.text = "❌ \(error?.localizedDescription ?? "Payment failed.")"
                            self.statusLabel.textColor = .systemRed
                            self.payButton.isEnabled = true
                            self.payButton.backgroundColor = .systemBlue
                        @unknown default:
                            break
                        }
                    }
                    
                case .failure(let error):
                    self.statusLabel.text = "❌ \(error.localizedDescription)"
                    self.statusLabel.textColor = .systemRed
                    self.payButton.isEnabled = true
                    self.payButton.backgroundColor = .systemBlue
                }
            }
        }
    }
    
    /// Calls your own backend to create a PaymentIntent and return the client secret.
    /// The Stripe SECRET key lives on the server, never in the mobile app.
    private func fetchPaymentIntentClientSecret(completion: @escaping (Result<String, Error>) -> Void) {
        // Replace with your actual backend URL
        guard let url = URL(string: "https://your-backend.example.com/create-payment-intent") else {
            completion(.failure(NSError(domain: "PaymentError", code: -1,
                                       userInfo: [NSLocalizedDescriptionKey: "Invalid backend URL. Configure your server endpoint."])))
            return
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        let body: [String: Any] = [
            "amount": demoAmount,
            "currency": "usd"
        ]
        request.httpBody = try? JSONSerialization.data(withJSONObject: body)
        
        URLSession.shared.dataTask(with: request) { data, _, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            
            guard let data = data,
                  let json = try? JSONSerialization.jsonObject(with: data) as? [String: Any],
                  let clientSecret = json["clientSecret"] as? String else {
                completion(.failure(NSError(domain: "PaymentError", code: -2,
                                           userInfo: [NSLocalizedDescriptionKey: "Invalid response from server."])))
                return
            }
            
            completion(.success(clientSecret))
        }.resume()
    }
}

